update course set title = #{title}
                , start_date = #{start_date}
                , end_date = #{end_date}
                , content = #{content}
                , notice = #{notice}
                , plan = #{plan}
                , class_id = #{classId}
                , time_code = #{time_code}
                , professor = #{professor}
                , sub_prof = #{sub_prof}
WHERE course_id = #{courseId}

mapper.select:
SELECT COUNT(*)
FROM course
WHERE course_isDeleted = 0   AND cos_sta_code != -1

AND course_id != #{courseId}


AND (
-- 1. 선택한 메인 강사(나)가 이미 해당 시간에 수업 중인지 (메인 혹은 보조로)
professor = #{professor}
OR sub_prof = #{professor}

-- 2. 선택한 강의실이 해당 시간에 이미 사용 중인지
OR class_id = #{classId}

-- 3. [추가] 선택한 보조 강사가 해당 시간에 이미 수업 중인지 (메인 혹은 보조로)

  OR professor = #{sub_prof}
  OR sub_prof = #{sub_prof}

)
AND time_code = #{time_code}

  -- 4. 날짜 기간이 겹치는지 확인
  AND start_date <= #{end_date}
  AND end_date >= #{start_date}
